      "snippet": "te> proc = ProcessState::self(); ALOGV(\"App process: starting thread pool.\\n\"); proc->startThreadPool(); } ProcessState::self(); frameworks/native/libs/binder/ProcessState.cpp #define BINDER_VM_SIZE ((1 * 1024 * 1024) - sysconf(_SC_PAGE_SIZE) * 2) sysconf(_SC_PAGE_SIZE)这个代表一页内存大小一般是 4096 这样 BINDER_VM_SIZE = 1M - 8k #define BINDER_VM_SIZE ((1 * 1024 * 1024) - sysconf(_SC_PAGE_SIZE) * 2) #define DEFAULT_MAX_BINDER_THREADS 15 sp<ProcessState> ProcessState::self() { Mutex::Autolock _l(gProcessMutex); if (gProcess != NULL) { return gProcess; } gProcess = new ProcessState(\"/dev/binder\"); return gProcess; } ProcessState::ProcessState(const char ",
